from flask import Flask, request, jsonify, g
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST, CollectorRegistry, multiprocess
import time
import os
import random

app = Flask(__name__)

registry = CollectorRegistry()
if "PROMETHEUS_MULTIPROC_DIR" in os.environ:
    multiprocess.MultiProcessCollector(registry)

REQUEST_COUNT = Counter(
    "flask_http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "http_status"],
    registry=registry,
)

REQUEST_LATENCY = Histogram(
    "flask_http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0),
    registry=registry,
)

IN_PROGRESS = Gauge(
    "flask_http_requests_in_progress",
    "In-progress HTTP requests",
    ["method", "endpoint"],
    registry=registry,
)

ACTIVE_USERS = Gauge(
    "business_active_users",
    "Current number of active users",
    registry=registry,
)

ORDERS_CREATED = Counter(
    "business_orders_created_total",
    "Total number of created orders",
    ["status"],
    registry=registry,
)

ORDER_VALUE = Histogram(
    "business_order_value",
    "Distribution of order values",
    buckets=(10, 25, 50, 100, 250, 500, 1000, 2500, 5000),
    registry=registry,
)

INVENTORY_LEVEL = Gauge(
    "business_inventory_level",
    "Current inventory level by product",
    ["product"],
    registry=registry,
)

PAYMENT_PROCESSING_TIME = Histogram(
    "business_payment_processing_seconds",
    "Payment processing duration in seconds",
    buckets=(0.01, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0),
    registry=registry,
)

FAILED_PAYMENTS = Counter(
    "business_failed_payments_total",
    "Total failed payments",
    ["reason"],
    registry=registry,
)

for product, level in {"widget": 120, "gadget": 75, "premium": 20}.items():
    INVENTORY_LEVEL.labels(product=product).set(level)

ACTIVE_USERS.set(42)


@app.before_request
def before_request():
    if request.path == "/metrics":
        return
    g.start_time = time.time()
    endpoint = request.endpoint or request.path
    g.endpoint_label = endpoint
    g.inprogress = IN_PROGRESS.labels(method=request.method, endpoint=endpoint)
    g.inprogress.inc()


@app.after_request
def after_request(response):
    if request.path == "/metrics":
        return response

    endpoint = getattr(g, "endpoint_label", request.endpoint or request.path)
    duration = time.time() - getattr(g, "start_time", time.time())

    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=endpoint,
        http_status=response.status_code,
    ).inc()

    REQUEST_LATENCY.labels(
        method=request.method,
        endpoint=endpoint,
    ).observe(duration)

    inprogress = getattr(g, "inprogress", None)
    if inprogress is not None:
        inprogress.dec()

    return response


@app.teardown_request
def teardown_request(exception=None):
    if request.path == "/metrics":
        return
    if exception is not None:
        inprogress = getattr(g, "inprogress", None)
        if inprogress is not None:
            try:
                inprogress.dec()
            except ValueError:
                pass


@app.route("/metrics")
def metrics():
    return generate_latest(registry), 200, {"Content-Type": CONTENT_TYPE_LATEST}


@app.route("/health")
def health():
    return jsonify({"status": "ok"})


@app.route("/users/active", methods=["GET", "POST"])
def users_active():
    if request.method == "GET":
        return jsonify({"active_users": ACTIVE_USERS._value.get()})
    data = request.get_json(silent=True) or {}
    value = int(data.get("active_users", 0))
    ACTIVE_USERS.set(value)
    return jsonify({"active_users": value})


@app.route("/orders", methods=["POST"])
def create_order():
    data = request.get_json(silent=True) or {}
    value = float(data.get("value", random.uniform(20, 500)))
    status = data.get("status", "success")
    product = data.get("product", "widget")
    quantity = int(data.get("quantity", 1))

    ORDER_VALUE.observe(value)

    processing_time = random.uniform(0.02, 0.7)
    time.sleep(min(processing_time, 0.2))
    PAYMENT_PROCESSING_TIME.observe(processing_time)

    if status != "success":
        FAILED_PAYMENTS.labels(reason=status).inc()
        ORDERS_CREATED.labels(status="failed").inc()
        return jsonify({"status": "failed", "reason": status}), 400

    ORDERS_CREATED.labels(status="success").inc()

    current_inventory = INVENTORY_LEVEL.labels(product=product)._value.get()
    INVENTORY_LEVEL.labels(product=product).set(max(0, current_inventory - quantity))

    return jsonify(
        {
            "status": "success",
            "product": product,
            "quantity": quantity,
            "value": value,
        }
    ), 201


@app.route("/inventory/<product>", methods=["GET", "POST"])
def inventory(product):
    metric = INVENTORY_LEVEL.labels(product=product)
    if request.method == "GET":
        return jsonify({"product": product, "inventory": metric._value.get()})

    data = request.get_json(silent=True) or {}
    level = int(data.get("level", 0))
    metric.set(level)
    return jsonify({"product": product, "inventory": level})


@app.route("/")
def index():
    return jsonify(
        {
            "service": "flask-prometheus-app",
            "endpoints": ["/", "/health", "/metrics", "/users/active", "/orders", "/inventory/<product>"],
        }
    )


if __name__ == "__main__":
    port = int(os.getenv("PORT", "5000"))
    app.run(host="0.0.0.0", port=port)